// // Script Continued Below
setEmptyPrivacyFieldsToOpen();

function setEmptyPrivacyFieldsToOpen(){
	// to run a test and only perform the counts, set testing to true
	var testing = false;

	updateEmptyPrivacy('x_153465_discovert_task_tree', 'u_privacy', testing);
	updateEmptyPrivacy('x_153465_discovert_route_task_instance', 'u_privacy', testing);
}

function updateEmptyPrivacy(table, privacy_field, testing){

	var numUpdated = 0;
	var privacyEmptyCount = countItemsToUpdate(table, privacy_field, testing);
	if(privacyEmptyCount>0){
		var rec = new GlideRecord(table);
		rec.addEncodedQuery("u_privacy!=open^u_privacy!=ou_private");
		rec.query();
		while(rec.next()) {
			var new_privacy = 'open'; // default to open
			if(table == 'x_153465_discovert_task_tree'){
				if(rec.u_task_ref && rec.u_task_ref.primary_office && rec.u_task_ref.primary_office.u_top_ou && 
					rec.u_task_ref.primary_office.u_top_ou.u_organizational_privacy){
					new_privacy = rec.u_task_ref.primary_office.u_top_ou.u_organizational_privacy;
				}
			} else if(table == 'x_153465_discovert_route_task_instance'){
				if(rec.primary_office && rec.primary_office.u_top_ou && 
					rec.primary_office.u_top_ou.u_organizational_privacy){
					new_privacy = rec.primary_office.u_top_ou.u_organizational_privacy;
				}
			}
			rec.setValue(privacy_field, new_privacy);
			rec.work_notes = 'Privacy set by Fix Script';

			if(!testing){
				rec.update();
				numUpdated +=1;
			}
		}

		switch(table){
			case 'x_153465_discovert_task_tree':
				if(numUpdated == privacyEmptyCount){
					gs.info("Fix Script - 2.8.401 - Default Privacy fields to open- the Privacy for all Task Trees has been set.");
				} else {
					gs.info("Fix Script - 2.8.401 - Default Privacy fields to open- Some Tasks with empty Privacy field were not updated. " + numUpdated + " of " + privacyEmptyCount + " were set. To see tasks with privacy not set, run this query on the Task table: u_privacy=" );
				}
				break;
			case 'x_153465_discovert_route_task_instance':
				if(numUpdated == privacyEmptyCount){
					gs.info("Fix Script - 2.8.401 - Default Privacy fields to open- the Privacy for all Tasks has been set.");
				} else {
					gs.info("Fix Script - 2.8.401 - Default Privacy fields to open- Some Tasks with empty Privacy field were not updated. " + numUpdated + " of " + privacyEmptyCount + " were set. To see tasks with privacy not set, run this query on the Task table: u_privacy=" );
				}
				break;
		}
	}
}

function countItemsToUpdate(table, privacy_field, value, testing){
	var privacyEmptyCount;
	// count all empty privacy fields
	var ga = new GlideAggregate(table);
	ga.addEncodedQuery("u_privacy!=open^u_privacy!=ou_private");
	ga.addAggregate("COUNT");	
	ga.query();
	if(ga.next()){
		privacyEmptyCount = ga.getAggregate("COUNT");
	}

	switch(table){
		case 'x_153465_discovert_task_tree':
			gs.info('Fix Script - 2.8.401 - Default Privacy fields to open - Your system was analyzed and ' + 
					privacyEmptyCount + ' Task Trees do not have privacy set.  Setting the privacy value to the value of the Primary Office for the Task Tree.');
			break;
		case 'x_153465_discovert_route_task_instance':
			gs.info('Fix Script - 2.8.401 - Default Privacy fields to open - Your system was analyzed and ' + 
					privacyEmptyCount + ' Tasks do not have privacy set.  Setting the privacy value to the value of the Primary Office for the top task in the tree.');
	}
	return privacyEmptyCount;
}
